  coordinates: {
    lat: number;
    lon: number;
  };
}
```

## utils/timeHelpers.ts

Created utility to parse opening hours strings (e.g., "12:00-23:00") and determine current status.

```typescript
import type { OpeningHours } from '../types';

export const getDayName = (date: Date): keyof OpeningHours => {
    const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    return days[date.getDay()] as keyof OpeningHours;
};

export const isOpenNow = (hours?: OpeningHours): { isOpen: boolean; statusText: string; nextTime?: string } => {
    if (!hours) return { isOpen: false, statusText: 'Hours unknown' };

    const now = new Date();
    const currentDay = getDayName(now);
    const timeString = hours[currentDay];

    if (!timeString || timeString === 'Closed') {
        return { isOpen: false, statusText: 'Closed today' };
    }

    const ranges = timeString.split(',').map(s => s.trim());
    const currentMinutes = now.getHours() * 60 + now.getMinutes();

    for (const range of ranges) {
        const [startStr, endStr] = range.split('-');
        if (!startStr || !endStr) continue;

        const [startH, startM] = startStr.split(':').map(Number);
        const [endH, endM] = endStr.split(':').map(Number);

        const startTotal = startH * 60 + startM;
        let endTotal = endH * 60 + endM;

        // Handle past midnight (e.g., 18:00-02:00)
        if (endTotal < startTotal) endTotal += 24 * 60;

        if (currentMinutes >= startTotal && currentMinutes < endTotal) {
            // Check if closing soon (within 1 hour)
            if (endTotal - currentMinutes < 60) {
                return { isOpen: true, statusText: 'Closing soon', nextTime: endStr };
            }
            return { isOpen: true, statusText: 'Open now', nextTime: endStr };
        }
    }

    return { isOpen: false, statusText: 'Closed now' };
};
```

## components/RestaurantStatus.tsx

Created a reusable component to display the Open/Closed status and link to Google.

```typescript
import React, { useState, useEffect } from 'react';
import { isOpenNow } from '../utils/timeHelpers';
import type { Restaurant } from '../types';

const RestaurantStatus: React.FC<{ restaurant: Restaurant; className?: string }> = ({ restaurant, className = "" }) => {
    const [status, setStatus] = useState<{ isOpen: boolean; statusText: string; nextTime?: string } | null>(null);

    useEffect(() => {
        setStatus(isOpenNow(restaurant.openingHours));
        // Update every minute
        const interval = setInterval(() => {
            setStatus(isOpenNow(restaurant.openingHours));
        }, 60000);
        return () => clearInterval(interval);
    }, [restaurant]);

    if (!status || status.statusText === 'Hours unknown') return null;

    const googleSearchUrl = `https://www.google.com/search?q=${encodeURIComponent(restaurant.name + ' opening hours')}`;

    return (
        <a 
            href={googleSearchUrl}
            target="_blank"
            rel="noopener noreferrer"
            className={`inline-flex items-center gap-2 group/status ${className}`}
            onClick={(e) => e.stopPropagation()}
            title="Verify on Google"
        >
            <span className="relative flex h-2.5 w-2.5">
                {status.isOpen && <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>}
                <span className={`relative inline-flex rounded-full h-2.5 w-2.5 ${status.isOpen ? (status.statusText === 'Closing soon' ? 'bg-orange-500' : 'bg-green-500') : 'bg-red-500'}`}></span>
            </span>
            <span className={`text-xs font-medium uppercase tracking-wider ${status.isOpen ? (status.statusText === 'Closing soon' ? 'text-orange-400' : 'text-green-400') : 'text-red-400/80'}`}>
                {status.statusText}
            </span>
            <span className="text-[10px] text-white/20 group-hover/status:text-white/50 transition-colors ml-1 border-b border-transparent group-hover/status:border-white/20">
                Check Google
            </span>
        </a>
    );
};

export default RestaurantStatus;
```

